const raw = $json.output || $json.text || $json.response || $json.message || JSON.stringify($json);

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let data;

try {
  data = JSON.parse(cleaned);
} catch (error) {
  throw new Error(
    "AI output is not valid JSON. Error: " +
    error.message +
    "\n\nRaw output:\n" +
    cleaned
  );
}

return [{ json: data }];

